mapper.select:
SELECT B1.* FROM ( SELECT A1.* , ROW_NUMBER() OVER( ORDER BY
A1.insertDt DESC
CAST(A1.${sortColumn} AS INTEGER) ${order}
A1.${sortColumn} ${order}
) AS PAGEINDEX FROM ( SELECT info.* , insertuser.USER_NM AS insertUserNm , updateUser.USER_NM AS updateUserNm , ecnInsert.USER_NM AS ecnUserNM
FROM ( SELECT info.BUSINESS_TYPE_CD AS businessTypeCd
, info.BUSINESS_PHASE AS businessTypeNm , info.DISTRIBUTE_TYPE_CD AS distributeTypeCd
, info.file_type AS distributeTypeNm , info.OBJECT_ID AS objectId , info.DOC_CLASS_CD2 AS docClassCd2 , FN_GET_CD_NM('docClassCd1', info.DOC_CLASS_CD1, 'ko') AS docClassNm2 , info.DOCUMENT_NO AS documentNo , info.DOCUMENT_NM AS documentNm , info.REV_NO AS revNo , info.INSERT_UID AS insertUid , info.UPDATE_UID AS updateUid , info.ecn_insert_uid AS ecn_insert_uid , info.REGISTER_USER AS registerUser , info.INSERT_DEPT_NM AS insertDeptNm , info.STD_GAPP_DT AS stdGappDt , info.CHANGE_GAPP_DT AS changeGappDt , info.ECN_NO AS ecnNo , info.BUSINESS_AREA_CD AS businessAreaCd , FN_GET_CD_NM('businessAreaCdAll', info.BUSINESS_AREA_CD, 'ko') AS businessAreaNm , info.PROTECT_YN AS protectYn , info.PROTECT_YN AS protectYnView , info.UPDATE_DT AS updateDt , info.INSERT_DT AS insertDt , info.approvaldate AS approvalDate , info.approver AS approver , COALESCE(fileInfo.PROCESSING_STATUS, '') AS processingStatus , CASE WHEN info.status = '승인완료' THEN '승인완료' WHEN COALESCE(NULLIF(TRIM(info.approver), ''), '') <> '' AND NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(info.approver, ' ', ''), ',') AS ap(token) WHERE COALESCE(NULLIF(TRIM(ap.token), ''), '') <> '' AND POSITION(',' || ap.token || ',' IN ',' || REPLACE(COALESCE(info.approved_users, info.status, ''), ' ', '') || ',') = 0 ) AND ( COALESCE(NULLIF(TRIM(info.reviewerUser), ''), '') = '' OR NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(info.reviewerUser, ' ', ''), ',') AS rv(token) WHERE COALESCE(NULLIF(TRIM(rv.token), ''), '') <> '' AND POSITION(',' || rv.token || ',' IN ',' || REPLACE(COALESCE(info.approved_users, info.status, ''), ' ', '') || ',') = 0 ) ) THEN '승인완료' ELSE '승인진행중' END AS status , info.coPublisher AS coPublisher , info.INTERFACE_DT AS interfaceDt , info.PRODUCT_CD AS productCd ,info.CURRENT_PAGE_NO AS currentPageNo ,info.TOTAL_PAGE_NO AS totalPageNo , COALESCE(info.PRODUCT_CD, '') AS productNm , ( SELECT COUNT(*) FROM DOCS_DOCUMENT_FILE documentFile WHERE documentFile.OBJECT_ID = info.OBJECT_ID ) AS fileCount , fileInfo.FILE_NO AS fileNo , fileInfo.ORG_FILE_NM AS fileViewNm , fileInfo.FILE_NM AS fileNm , fileInfo.FILE_SIZE AS fileSize , fileInfo.ORG_FILE_NM AS orgFileNm , fileInfo.FILE_PATH_NM AS filePath , info.VALID_TYPE AS validType , DENSE_RANK() OVER (PARTITION BY DOCUMENT_NO ORDER BY DOCUMENT_NO, LENGTH(REV_NO), REV_NO DESC) AS rnk FROM DOCS_DOCUMENT_FILE fileInfo JOIN DOCS_DOCUMENT info ON fileInfo.OBJECT_ID = info.OBJECT_ID
FROM ( SELECT info.BUSINESS_TYPE_CD AS businessTypeCd
, info.BUSINESS_PHASE AS businessTypeNm , info.DISTRIBUTE_TYPE_CD AS distributeTypeCd , info.FILE_TYPE AS distributeTypeNm , info.OBJECT_ID AS objectId , info.DOC_CLASS_CD2 AS docClassCd2 , FN_GET_CD_NM('docClassCd1', info.DOC_CLASS_CD1, 'ko') AS docClassNm2 , info.DOCUMENT_NO AS documentNo , info.DOCUMENT_NM AS documentNm , info.REV_NO AS revNo , info.INSERT_UID AS insertUid , info.UPDATE_UID AS updateUid ,info.CURRENT_PAGE_NO AS currentPageNo ,info.TOTAL_PAGE_NO AS totalPageNo , info.ecn_insert_uid AS ecn_insert_uid , info.REGISTER_USER AS registerUser , info.INSERT_DEPT_NM AS insertDeptNm , info.STD_GAPP_DT AS stdGappDt , info.CHANGE_GAPP_DT AS changeGappDt , info.ECN_NO AS ecnNo , info.BUSINESS_AREA_CD AS businessAreaCd , FN_GET_CD_NM('businessAreaCdAll', info.BUSINESS_AREA_CD, 'ko') AS businessAreaNm , info.PROTECT_YN AS protectYn , info.PROTECT_YN AS protectYnView , info.UPDATE_DT AS updateDt , info.INSERT_DT AS insertDt , info.approvaldate AS approvalDate , info.approver AS approver , COALESCE(fileInfo.PROCESSING_STATUS, '') AS processingStatus , CASE WHEN info.status = '승인완료' THEN '승인완료' WHEN COALESCE(NULLIF(TRIM(info.approver), ''), '') <> '' AND NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(info.approver, ' ', ''), ',') AS ap(token) WHERE COALESCE(NULLIF(TRIM(ap.token), ''), '') <> '' AND POSITION(',' || ap.token || ',' IN ',' || REPLACE(COALESCE(info.approved_users, info.status, ''), ' ', '') || ',') = 0 ) AND ( COALESCE(NULLIF(TRIM(info.reviewerUser), ''), '') = '' OR NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(info.reviewerUser, ' ', ''), ',') AS rv(token) WHERE COALESCE(NULLIF(TRIM(rv.token), ''), '') <> '' AND POSITION(',' || rv.token || ',' IN ',' || REPLACE(COALESCE(info.approved_users, info.status, ''), ' ', '') || ',') = 0 ) ) THEN '승인완료' ELSE '승인진행중' END AS status , info.coPublisher AS coPublisher , info.CREATE_DT AS createDt , info.INTERFACE_DT AS interfaceDt , info.PRODUCT_CD AS productCd , COALESCE(info.PRODUCT_CD, '') AS productNm , ( SELECT COUNT(*) FROM DOCS_DOCUMENT_FILE documentFile WHERE documentFile.OBJECT_ID = info.OBJECT_ID ) AS fileCount , fileInfo.FILE_NO AS fileNo , fileInfo.ORG_FILE_NM AS fileViewNm , fileInfo.FILE_NM AS fileNm , fileInfo.FILE_SIZE AS fileSize , fileInfo.ORG_FILE_NM AS orgFileNm , fileInfo.FILE_PATH_NM AS filePath , info.VALID_TYPE AS validType FROM DOCS_DOCUMENT_FILE fileInfo JOIN DOCS_DOCUMENT info ON fileInfo.OBJECT_ID = info.OBJECT_ID
WHERE 1=1 AND info.DELETED_YN = 'N'
AND BUSINESS_AREA_CD LIKE '%' || #{businessAreaCd} || '%'
AND BUSINESS_TYPE_CD = #{businessTypeCd}
AND DOCUMENT_NO = UPPER(TRIM(#{documentNo}))
AND DOCUMENT_NO LIKE '%' || UPPER(TRIM(#{documentNo})) || '%'
AND EXISTS ( SELECT 1 FROM DOCS_DOCUMENT_TREE docTree , DOCS_DOCUMENT_TREE selectedTree WHERE TRIM(docTree.TREE_CD) = TRIM(info.TREE_CD) AND TRIM(selectedTree.TREE_CD) = TRIM(#{docTreeCd}) AND docTree.TREE_PATH LIKE selectedTree.TREE_PATH || '%' )
AND DOCUMENT_NM LIKE '%' || #{documentNm} || '%'
AND DOC_CLASS_CD2 = #{docClassCd2}
AND info.DISTRIBUTE_TYPE_CD = #{distributeTypeCd}
AND info.DISTRIBUTE_TYPE_NM = #{distributeTypeNm}
AND ECN_NO LIKE '%' || UPPER(TRIM(#{ecnNo})) || '%'
AND PRODUCT_CD = #{productCd}
AND INSERT_UID = #{insertUid}
AND UPPER(DOC_CLASS_NM2) LIKE '%' || UPPER(TRIM(#{docClassNm2})) || '%'
AND VALID_TYPE IS NULL
AND VALID_TYPE = 'N'
AND info.INTERFACE_DT BETWEEN TO_DATE(#{interfaceStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{interfaceEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
AND(
(DOCUMENT_NO LIKE '%' || UPPER(TRIM(#{documentInfo.documentNo})) || '%')
)
AND(
(DOCUMENT_NO = UPPER(TRIM(#{documentInfo.documentNo})) )
)
) info LEFT JOIN DOCS_USER insertUser ON insertUser.USER_ID = info.insertUid LEFT JOIN DOCS_USER updateUser ON updateUser.USER_ID = info.updateUid LEFT jOIN DOCS_USER ecnInsert ON ecnInsert.USER_ID = info.ecn_insert_uid
WHERE rnk = 1
ORDER BY insertDT DESC, documentNo, revNo DESC, fileNo
ORDER BY ${sortColumn} ${order}
) A1 ) B1 WHERE 1=1
AND PAGEINDEX <= #{end}
AND PAGEINDEX >= #{start}

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT A1.* FROM ( SELECT info.* , insertuser.USER_NM AS insertUserNm , updateUser.USER_NM AS updateUserNm
FROM ( SELECT info.BUSINESS_TYPE_CD AS businessTypeCd , FN_GET_CD_NM('businessTypeCd', info.BUSINESS_TYPE_CD, 'ko') AS businessTypeNm , info.DISTRIBUTE_TYPE_CD AS distributeTypeCd -- , FN_GET_CD_NM('distributeTypeCd', info.DISTRIBUTE_TYPE_CD, 'ko') AS distributeTypeNm , info.FILE_TYPE AS distributeTypeNm , info.OBJECT_ID AS objectId , info.DOC_CLASS_CD2 AS docClassCd2 , FN_GET_CD_NM('docClassCd1', info.DOC_CLASS_CD1, 'ko') AS docClassNm2 , info.DOCUMENT_NO AS documentNo , info.DOCUMENT_NM AS documentNm , info.REV_NO AS revNo , info.INSERT_UID AS insertUid , info.UPDATE_UID AS updateUid , info.ecn_insert_uid AS ecn_insert_uid , info.REGISTER_USER AS registerUser , info.INSERT_DEPT_NM AS insertDeptNm , info.STD_GAPP_DT AS stdGappDt , info.CHANGE_GAPP_DT AS changeGappDt , info.ECN_NO AS ecnNo , info.BUSINESS_AREA_CD AS businessAreaCd , FN_GET_CD_NM('businessAreaCdAll', info.BUSINESS_AREA_CD, 'ko') AS businessAreaNm , info.PROTECT_YN AS protectYn , info.PROTECT_YN AS protectYnView , info.UPDATE_DT AS updateDt , info.INSERT_DT AS insertDt , info.CREATE_DT AS createDt , info.INTERFACE_DT AS interfaceDt , info.PRODUCT_CD AS productCd , COALESCE(info.PRODUCT_CD, '') AS productNm , ( SELECT COUNT(*) FROM DOCS_DOCUMENT_FILE documentFile WHERE documentFile.OBJECT_ID = info.OBJECT_ID ) AS fileCount , fileInfo.FILE_NO AS fileNo , fileInfo.ORG_FILE_NM AS fileViewNm , fileInfo.FILE_NM AS fileNm , fileInfo.FILE_SIZE AS fileSize , fileInfo.ORG_FILE_NM AS orgFileNm , fileInfo.FILE_PATH_NM AS filePath , info.VALID_TYPE AS validType , DENSE_RANK() OVER (PARTITION BY DOCUMENT_NO ORDER BY REV_NO DESC) as rnk FROM DOCS_DOCUMENT_FILE fileInfo JOIN DOCS_DOCUMENT info ON fileInfo.OBJECT_ID = info.OBJECT_ID
FROM ( SELECT info.BUSINESS_TYPE_CD AS businessTypeCd , FN_GET_CD_NM('businessTypeCd', info.BUSINESS_TYPE_CD, 'ko') AS businessTypeNm , info.DISTRIBUTE_TYPE_CD AS distributeTypeCd -- , FN_GET_CD_NM('distributeTypeCd', info.DISTRIBUTE_TYPE_CD, 'ko') AS distributeTypeNm , info.FILE_TYPE AS distributeTypeNm , info.OBJECT_ID AS objectId , info.DOC_CLASS_CD2 AS docClassCd2 , info.DOC_CLASS_NM2 AS docClassNm2 , info.DOCUMENT_NO AS documentNo , info.DOCUMENT_NM AS documentNm , info.REV_NO AS revNo , info.INSERT_UID AS insertUid , info.UPDATE_UID AS updateUid , info.ecn_insert_uid AS ecn_insert_uid , info.REGISTER_USER AS registerUser , info.INSERT_DEPT_NM AS insertDeptNm , info.STD_GAPP_DT AS stdGappDt , info.CHANGE_GAPP_DT AS changeGappDt , info.ECN_NO AS ecnNo , info.BUSINESS_AREA_CD AS businessAreaCd , FN_GET_CD_NM('businessAreaCdAll', info.BUSINESS_AREA_CD, 'ko') AS businessAreaNm , info.PROTECT_YN AS protectYn , info.PROTECT_YN AS protectYnView , info.UPDATE_DT AS updateDt , info.INSERT_DT AS insertDt , info.CREATE_DT AS createDt , info.CREATE_DT AS createDt , info.INTERFACE_DT AS interfaceDt , info.PRODUCT_CD AS productCd , COALESCE(info.PRODUCT_CD, '') AS productNm , ( SELECT COUNT(*) FROM DOCS_DOCUMENT_FILE documentFile WHERE documentFile.OBJECT_ID = info.OBJECT_ID ) AS fileCount , fileInfo.FILE_NO AS fileNo , fileInfo.ORG_FILE_NM AS fileViewNm , fileInfo.FILE_NM AS fileNm , fileInfo.FILE_SIZE AS fileSize , fileInfo.ORG_FILE_NM AS orgFileNm , fileInfo.FILE_PATH_NM AS filePath , info.VALID_TYPE AS validType FROM DOCS_DOCUMENT_FILE fileInfo JOIN DOCS_DOCUMENT info ON fileInfo.OBJECT_ID = info.OBJECT_ID
WHERE 1=1 AND info.DELETED_YN = 'N'
AND BUSINESS_AREA_CD LIKE '%' || #{businessAreaCd} || '%'
AND BUSINESS_TYPE_CD = #{businessTypeCd}
AND DOCUMENT_NO = UPPER(TRIM(#{documentNo}))
AND DOCUMENT_NO LIKE '%' || UPPER(TRIM(#{documentNo})) || '%'
AND EXISTS ( SELECT 1 FROM DOCS_DOCUMENT_TREE docTree , DOCS_DOCUMENT_TREE selectedTree WHERE TRIM(docTree.TREE_CD) = TRIM(info.TREE_CD) AND TRIM(selectedTree.TREE_CD) = TRIM(#{docTreeCd}) AND docTree.TREE_PATH LIKE selectedTree.TREE_PATH || '%' )
AND DOCUMENT_NM LIKE '%' || #{documentNm} || '%'
AND DOC_CLASS_CD2 = #{docClassCd2}
AND UPPER(DOC_CLASS_NM2) LIKE '%' || UPPER(TRIM(#{docClassNm2})) || '%'
AND info.DISTRIBUTE_TYPE_NM = #{distributeTypeNm}
AND ECN_NO LIKE '%' || UPPER(TRIM(#{ecnNo})) || '%'
AND PRODUCT_CD = #{productCd}
AND INSERT_UID = #{insertUid}
AND VALID_TYPE IS NULL
AND VALID_TYPE = 'N'
AND info.INTERFACE_DT BETWEEN TO_DATE(#{interfaceStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{interfaceEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
AND(
(DOCUMENT_NO LIKE '%' || UPPER(TRIM(#{documentInfo.documentNo})) || '%')
)
AND(
(DOCUMENT_NO = UPPER(TRIM(#{documentInfo.documentNo})) )
)
) info LEFT JOIN DOCS_USER insertUser ON insertUser.USER_ID = info.insertUid LEFT JOIN DOCS_USER updateUser ON updateUser.USER_ID = info.updateUid
WHERE rnk = 1
) A1 ) B1

mapper.insert:

	/* */
	SELECT COALESCE(MAX(CAST(CN_SERIAL AS INTEGER)),0)+1 AS cnSerial
	FROM DOCS_DOCUMENT

/* DOCS_DOCUMENT 추가 */
INSERT INTO DOCS_DOCUMENT
( OBJECT_ID
, CN_SERIAL
, INSERT_DT
, BUSINESS_AREA_CD
, BUSINESS_TYPE_CD
, DOCUMENT_NO
, TREE_CD
, DOCUMENT_NM
, DISTRIBUTE_TYPE_CD
, FILE_TYPE
, PROTECT_YN
, INSERT_UID
, REGISTER_USER
, approvaldate
, approver
, STATUS
, coPublisher
, revieweruser
, REV_NO
, DOC_CLASS_CD1
)

VALUES
( #{objectId}
, CAST(#{cnSerial} AS INTEGER)
, CURRENT_TIMESTAMP
, #{sessionUser.businessAreaCd}
, #{businessTypeCd}
, #{docNo}
, #{treeCd}
, #{fileNm}
, #{distributeTypeCd}
, #{fileType}
, #{protectYn}
, #{sessionUser.userId}
, COALESCE(NULLIF(#{sessionUser.userNm}, ''), #{sessionUser.username})
, #{approvalDate}
, #{approver}
, '승인진행중'
, COALESCE(NULLIF(#{coPublisher}, ''), COALESCE(NULLIF(#{sessionUser.userNm}, ''), #{sessionUser.username}))
, #{reviewerUser}
, #{revNo}
, #{docClassCd1}
)

/* 조회 */ SELECT COALESCE(MAX(CAST(CN_SERIAL AS INTEGER)),0)+0 AS cnSerial FROM DOCS_DOCUMENT
/* DOCS_DOCUMENT_FILE 추가 */ INSERT INTO DOCS_DOCUMENT_FILE ( OBJECT_ID , CN_SERIAL , INTERFACE_DT , FILE_SIZE , ORG_FILE_NM , FILE_NO , DISTRIBUTE_TYPE_CD , FILE_PATH_NM , REGISTER_USER , PROCESSING_STATUS , PROCESSING_ERROR , PROCESSED_AT )
VALUES ( #{objectId} , CAST(#{cnSerial} AS INTEGER) , CURRENT_TIMESTAMP , #{fileSize} , #{orgFileNm} , 1 , #{distributeTypeCd} , #{filePath} , COALESCE(NULLIF(#{sessionUser.userNm}, ''), #{sessionUser.username}) , 'PROCESSING' , NULL , NULL )

mapper.select:
SELECT OBJECT_ID
FROM DOCS_DOCUMENT_FILE
WHERE OBJECT_ID = #{objectId}

SELECT mainFile.OBJECT_ID AS "objectId", CAST(mainFile.FILE_NO AS TEXT) AS "fileNo", mainFile.ORG_FILE_NM AS "orgFileNm", mainFile.FILE_PATH_NM AS "filePath" FROM DOCS_DOCUMENT_FILE mainFile JOIN DOCS_DOCUMENT document ON document.OBJECT_ID = mainFile.OBJECT_ID WHERE mainFile.OBJECT_ID = #{objectId} AND COALESCE(document.DELETED_YN, 'N') = 'N' AND CAST(mainFile.FILE_NO AS INTEGER) = 1
AND CAST(mainFile.FILE_NO AS TEXT) = #{fileNo}
UNION ALL SELECT subFile.OBJECT_ID AS "objectId", CAST(subFile.FILE_NO AS TEXT) AS "fileNo", subFile.ORG_FILE_NM AS "orgFileNm", subFile.FILE_PATH_NM AS "filePath" FROM DOCS_DOCUMENT_SUB_FILE subFile WHERE subFile.OBJECT_ID = #{objectId} AND COALESCE(subFile.USE_YN, 'Y') = 'Y'
AND CAST(subFile.FILE_NO AS TEXT) = #{fileNo}
LIMIT 1
